        Console.WriteLine("\n=== MICROSOFT.EXTENSIONS.AI ===\n");
        PrintPublicTypes(extAI);

        Console.WriteLine("\n=== MICROSOFT.AGENTS.AI ===\n");
        PrintPublicTypes(agentsAI);

        Console.WriteLine("\n=== MICROSOFT.EXTENSIONS.AI.OPENAI ===\n");
        PrintPublicTypes(openAI);
    }

    static void PrintPublicTypes(Assembly assembly)
    {
        var types = assembly.GetTypes()
            .Where(t => t.IsPublic && !t.Name.Contains("<"))
            .OrderBy(t => t.Name)
            .ToList();

        foreach (var type in types)
        {
            Console.WriteLine($"{GetTypeKind(type)} {type.FullName}");

            if (type.IsInterface)
            {
                PrintMembers(type);
            }
            else if (type.IsClass && !type.IsAbstract && (type.Name.Contains("Client") || type.Name.Contains("Agent") || type.Name.Contains("Tool") || type.Name.Contains("Message") || type.Name.Contains("Options")))
            {
                PrintMembers(type);
            }
        }
    }

    static void PrintMembers(Type type)
    {
        var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static)
            .Where(m => !m.IsSpecialName)
            .GroupBy(m => m.Name)
            .ToList();

        if (methods.Count > 0)
        {
            foreach (var methodGroup in methods.Take(5))
            {
                foreach (var method in methodGroup.Take(1))
                {
                    var parms = string.Join(", ", method.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
                    Console.WriteLine($"  {method.ReturnType.Name} {method.Name}({parms})");
                }
            }
            if (methods.Count > 5)
                Console.WriteLine($"  ... and {methods.Count - 5} more methods");
        }
    }

    static string GetTypeKind(Type type)
    {
        if (type.IsInterface) return "interface";
        if (type.IsEnum) return "enum";
        if (type.IsValueType) return "struct";
        if (type.IsAbstract) return "abstract class";
        return "class";
    }
}
