// Web Search Tool — uses DuckDuckGo HTML (no API key required)
// ═══════════════════════════════════════════════════════════════════════════
static class WebSearchTool
{
    private static readonly HttpClient Http = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" }
        },
        Timeout = TimeSpan.FromSeconds(15)
    };

    [Description("Search the web for information on a query. Returns a list of result titles and URLs.")]
    public static async Task<string> SearchAsync(
        [Description("The search query string")] string query)
    {
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";
            var html = await Http.GetStringAsync(url);

            var results = ParseSearchResults(html);
            if (results.Count == 0)
                return "No results found.";

            var sb = new StringBuilder();
            sb.AppendLine($"Search results for: {query}");
            sb.AppendLine();
            for (var i = 0; i < Math.Min(results.Count, 8); i++)
            {
                var (title, link, snippet) = results[i];
                sb.AppendLine($"{i + 1}. {title}");
                sb.AppendLine($"   URL: {link}");
                if (!string.IsNullOrWhiteSpace(snippet))
                    sb.AppendLine($"   {snippet}");
                sb.AppendLine();
            }

            return sb.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Fetch the text content of a web page given its URL. Returns the page text (truncated to a reasonable length).")]
    public static async Task<string> FetchPageAsync(
        [Description("The URL of the page to fetch")] string url)
    {
        try
        {
            var html = await Http.GetStringAsync(url);
            var text = StripHtmlTags(html);

            // Collapse whitespace
            text = System.Text.RegularExpressions.Regex.Replace(text, @"\s+", " ").Trim();

            const int maxLength = 6000;
            if (text.Length > maxLength)
                text = text[..maxLength] + "… [truncated]";

            return $"Content from {url}:\n\n{text}";
        }
        catch (Exception ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    private static List<(string Title, string Url, string Snippet)> ParseSearchResults(string html)
    {
        var results = new List<(string, string, string)>();

        // Parse DuckDuckGo HTML search results
        var linkPattern = new System.Text.RegularExpressions.Regex(
            @"<a[^>]+class=""result__a""[^>]*href=""([^""]*?)""[^>]*>(.*?)</a>",
            System.Text.RegularExpressions.RegexOptions.Singleline);

        var snippetPattern = new System.Text.RegularExpressions.Regex(
            @"<a[^>]+class=""result__snippet""[^>]*>(.*?)</a>",
            System.Text.RegularExpressions.RegexOptions.Singleline);

        var linkMatches = linkPattern.Matches(html);
        var snippetMatches = snippetPattern.Matches(html);

        for (var i = 0; i < linkMatches.Count; i++)
        {
            var rawUrl = linkMatches[i].Groups[1].Value;
            var title = StripHtmlTags(linkMatches[i].Groups[2].Value).Trim();

            // DuckDuckGo wraps URLs in a redirect; extract the actual URL
            var actualUrl = ExtractDdgUrl(rawUrl);

            var snippet = i < snippetMatches.Count
                ? StripHtmlTags(snippetMatches[i].Groups[1].Value).Trim()
                : string.Empty;

            if (!string.IsNullOrWhiteSpace(title) && !string.IsNullOrWhiteSpace(actualUrl))
                results.Add((title, actualUrl, snippet));
        }

        return results;
    }

    private static string ExtractDdgUrl(string ddgUrl)
    {
        // DuckDuckGo redirects look like: //duckduckgo.com/l/?uddg=<encoded>&...
        if (ddgUrl.Contains("uddg="))
        {
            var match = System.Text.RegularExpressions.Regex.Match(ddgUrl, @"uddg=([^&]+)");
            if (match.Success)
                return Uri.UnescapeDataString(match.Groups[1].Value);
        }

        return ddgUrl;
    }

    private static string StripHtmlTags(string html)
    {
        // Decode common HTML entities
        var text = html
            .Replace("&amp;", "&")
            .Replace("&lt;", "<")
            .Replace("&gt;", ">")
            .Replace("&quot;", "\"")
            .Replace("&#39;", "'")
            .Replace("&nbsp;", " ");

        // Remove tags
        text = System.Text.RegularExpressions.Regex.Replace(text, @"<style[^>]*>.*?</style>", " ",
            System.Text.RegularExpressions.RegexOptions.Singleline);
        text = System.Text.RegularExpressions.Regex.Replace(text, @"<script[^>]*>.*?</script>", " ",
            System.Text.RegularExpressions.RegexOptions.Singleline);
        text = System.Text.RegularExpressions.Regex.Replace(text, @"<[^>]+>", " ");

        return text;
    }
}

