// Notebook Tool — simple in-memory note store
// ═══════════════════════════════════════════════════════════════════════════
class Notebook
{
    private readonly List<string> _notes = [];

    [Description("Save a research note. Use this to record key findings, facts, or quotes as you discover them.")]
    public string AddNote(
        [Description("The note text to save")] string note)
    {
        _notes.Add(note);
        return $"Note #{_notes.Count} saved.";
    }

    [Description("Retrieve all saved research notes collected so far.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        var sb = new StringBuilder();
        sb.AppendLine($"Collected notes ({_notes.Count} total):");
        sb.AppendLine();
        for (var i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"[{i + 1}] {_notes[i]}");
            sb.AppendLine();
        }

        return sb.ToString();
    }

    public void Clear() => _notes.Clear();
}

